def create_gateway_server(
    gateway_port: int,
    backend_configs: List[BackendServiceConfig],
    gateway_id: str = "api-gateway-1",
) -> Tuple[grpc.Server, ServiceRegistry, GatewayGrpcClient]:
    """Create and configure the gateway server."""

    # Set up service registry
    registry = ServiceRegistry()
    for config in backend_configs:
        registry.register(config)

    # Create the gateway client
    client = GatewayGrpcClient(service_registry=registry, gateway_id=gateway_id)

    # Create the gateway servicer
    servicer = GatewayServiceServicer(client=client)

    # Create gRPC server
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))

    # In production, you would add the servicer to the server using generated code:
    # gateway_pb2_grpc.add_GatewayServiceServicer_to_server(servicer, server)

    server.add_insecure_port(f"[::]:{gateway_port}")

    return server, registry, client


