def run_gateway_server():
    """Run the actual gateway server (for production use)."""
    import signal
    import sys

    backend_configs = [
        BackendServiceConfig(name="user-service", host="localhost", port=50051),
        BackendServiceConfig(name="order-service", host="localhost", port=50052),
        BackendServiceConfig(name="payment-service", host="localhost", port=50053),
    ]

    server, registry, client = create_gateway_server(
        gateway_port=8080,
        backend_configs=backend_configs,
        gateway_id="api-gateway-prod-1",
    )

    def shutdown(signum, frame):
        print("\n[Gateway] Shutting down...")
        server.stop(grace=5)
        registry.close_all()
        sys.exit(0)

    signal.signal(signal.SIGINT, shutdown)
    signal.signal(signal.SIGTERM, shutdown)

    server.start()
    print("[Gateway] API Gateway gRPC server started on port 8080")
    print("[Gateway] Registered backend services:")
    for name, config in registry._services.items():
        print(f"  - {name}: {config.host}:{config.port} (TLS: {config.use_tls})")

    server.wait_for_termination()


